// ── helpers ────────────────────────────────────────────────────────────────
const fmtMin = s => s ? `${Math.round(s/60)} min` : '—';

function seededShuffle(arr, seed) {
  const a = [...arr];
  let s = seed;
  for (let i = a.length - 1; i > 0; i--) {
    s = (s * 1664525 + 1013904223) & 0xffffffff;
    const j = Math.abs(s) % (i + 1);
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Pick n random unique items from arr, avoiding exclude list
function pick(arr, n, exclude = [], seed = Date.now()) {
  const pool = arr.filter(x => !exclude.includes(x));
  const shuffled = seededShuffle(pool, seed + arr.length);
  return n === 1 ? shuffled[0] : shuffled.slice(0, n);
}

function isBreathworkMove(name = '') {
  const normalized = String(name).toLowerCase();
  return normalized.includes('breath') || normalized.includes('breathe');
}

function getComparablePattern(pattern) {
  if (!pattern) return null;
  const normalizeType = (type = '') => type.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
  const targetType = normalizeType(pattern.type);
  const matches = DATA.workoutPatterns.filter(ref => {
    const refType = normalizeType(ref.type);
    return refType === targetType || refType.includes(targetType) || targetType.includes(refType);
  });

  if (!matches.length) return null;
  return [...matches].sort((a, b) => Math.abs((a.duration || 0) - (pattern.duration || 0)) - Math.abs((b.duration || 0) - (pattern.duration || 0)))[0];
}

